example.code:
it('submits the form', async () => {
  const spy = jest.spyOn(api, 'createUser');
  await submitForm(validData);
  expect(spy).toHaveBeenCalled();   // structural: was called, but didn't check result
  expect(spy).toHaveBeenCalledTimes(1);
});

it('submits the form and persists user', async () => {
  const res = await submitForm(validData);
  expect(res.status).toBe(201);
  expect(res.body.user_id).toMatch(/^usr_/);
  const persisted = await db.users.find({ email: validData.email });
  expect(persisted).toBeDefined();
  expect(persisted.created_at).toBeRecentTimestamp();
});
